{
  "id": "module_rainy_town_001",
  "version": "1.0",
  "world_id": "rainy_town_001",
  "name": "水影迷踪",
  "player_count_min": 2,
  "player_count_max": 4,
  "duration_minutes": 90,
  "opening_hook": "连续三周的暴雨让雨镇笼罩在潮湿与不安中。今日清晨，镇口祠堂的守灵人沈伯失踪了——他昨晚明明还在祠堂守夜，今早却只留下一滩积水。你们（调查者）是收到匿名举报信后赶到镇上的，信上只有一句话：‘水里的东西快出来了。’",
  "core_secret": "古井中镇压的并非单一怨念，而是数百年前因水患被献祭的整个村庄的集体执念。它们通过‘水影’附身活人，替换人的影子，最终取代其身份。守门人家族每隔九十年需要举行一次‘换水’仪式，用活人的记忆与情感加固封印。现任守门人沈伯为了阻止最后一次换水（因为他不想牺牲无辜者），故意打开了封印的裂缝，导致水影外溢，他自己也被反噬失踪。",
  "major_conflict": "水影正在逐渐侵蚀雨镇居民的影子，已有至少五人被替换，他们潜伏在镇上试图完成‘影占人’的过程。同时，市调查组中混入了一名被水影替换的成员，正试图引导调查者误入歧途，破坏任何可能重新封印的尝试。调查者必须在七十二小时内（湿气值达到临界前）找到沈伯，修复封印，否则全镇将被水影吞噬。",
  "required_npcs": [
    {
      "name": "沈伯",
      "description": "守门人家族现任传人，六十多岁，失踪前留下关键线索",
      "role": "关键NPC，失踪者，掌握封印方法"
    },
    {
      "name": "小沈（沈玉）",
      "description": "沈伯的孙女，二十出头，在镇卫生院当护士，对祖父的失踪忧心忡忡，但知道一些秘密",
      "role": "盟友NPC，提供情报与帮助"
    },
    {
      "name": "李队长",
      "description": "市调查组组长，沉默寡言，但似乎知道内情。实际已被水影替换（玩家需发现）",
      "role": "敌对NPC（伪装）"
    },
    {
      "name": "陈阿婆",
      "description": "镇上的老茶客，九十岁，知道许多关于换水仪式的传说",
      "role": "线索NPC"
    }
  ],
  "key_locations": [
    {
      "name": "沈家旧宅天井",
      "description": "中央积水的天井，水底能看到模糊的人影倒映，是连接镜像世界的入口之一"
    },
    {
      "name": "镇口祠堂后院古井",
      "description": "被铁链和符咒封住的井口，井水呈墨黑色，散发出腥味，是最后的封印点"
    },
    {
      "name": "废弃镇卫生院地下室",
      "description": "失踪案最后发生的地点，地下有积水，墙壁上刻有古老的咒文，是水影活动的巢穴"
    },
    {
      "name": "雨巷中的青砖墙",
      "description": "其中一块砖下藏着沈伯留下的日记残页，记录了换水仪式的细节"
    }
  ],
  "key_clues": [
    {
      "clue": "沈伯日记残页（在雨巷青砖下发现）",
      "description": "记载了‘水影是村庄集体的执念’和‘换水需要活人的记忆与情感’，并提到‘我不能再看着任何人被献祭’。",
      "points_to": "核心秘密（古井镇压的是集体执念，换水仪式需要牺牲）"
    },
    {
      "clue": "镇卫生院地下室墙上的咒文拓片",
      "description": "咒文内容为‘以血肉封影，以记忆养水’，与日记中换水仪式描述吻合，且咒文被新刻的划痕破坏了一部分。",
      "points_to": "核心秘密（封印被故意破坏）"
    },
    {
      "clue": "陈阿婆的口述",
      "description": "她记得九十年一次的‘大祭’，提到‘上一次是光绪年间，整个村都安静了三天’，并说‘沈家老祖宗把那么多人的影子收进井里，欠的债总要还’。",
      "points_to": "核心秘密（集体执念的由来与封印代价）"
    },
    {
      "clue": "李队长的异常行为记录（从他的手下口中得到）",
      "description": "李队长最近总是避开水洼，从不照镜子，且右手腕有一道水纹状的伤痕。与失踪者描述的被替换者特征一致。",
      "points_to": "核心秘密（水影替换活人的证据）"
    }
  ],
  "threat_clock_id": "threat_clock_rainy_town_001",
  "endings": [
    {
      "type": "good",
      "description": "调查者们找到沈伯（被困在镜像世界），利用日记和咒文知识修复封印，将被替换的居民恢复正常。李队长被揭露并驱逐。雨镇恢复平静。"
    },
    {
      "type": "partial",
      "description": "封印被修复，但沈伯牺牲了自己来填补裂缝。水影被暂时压制，但仍有残留，部分被替换者无法复原。调查者背负着水债离开。"
    },
    {
      "type": "bad",
      "description": "封印彻底崩溃，整个雨镇被水影吞噬，所有的影子替换了主人。调查者也被困在镜像世界中，成为新的‘祭品’。"
    }
  ],
  "ai_do_not_change": [
    "古井中镇压的是数百年前因水患被献祭的整个村庄的集体执念。",
    "水影替换人的影子的机制必须保留。",
    "换水仪式需要活人的记忆与情感来加固封印。",
    "现任守门人沈伯是主动打开封印裂缝的。",
    "市调查组组长李队长已被水影替换。",
    "调查者必须在场景中用湿气值机制（来自世界草案）来感知危机。",
    "最终结局判定基于是否找到沈伯、是否修复封印、是否击败被替换的水影。"
  ],
  "ai_freedom_level": "medium"
}
